#!/usr/bin/env python3
from pathlib import Path
import runpy
import sys
import os
SOURCE = '"""Deterministic resampling stability selection with local preprocessing."""\n\nimport argparse\nimport json\nfrom dataclasses import dataclass\nfrom pathlib import Path\nfrom typing import Any, Sequence\n\nimport numpy as np\n\n\n@dataclass(frozen=True)\nclass StabilityResult:\n    selected_indices: list[int]\n    selected_features: list[str]\n    frequencies: np.ndarray\n    threshold: float\n    n_resamples: int\n\n\ndef _as_matrix(X: Any) -> np.ndarray:\n    arr = np.asarray(X, dtype=np.float64)\n    if arr.ndim != 2 or arr.shape[0] < 2 or arr.shape[1] == 0:\n        raise ValueError("X must be a two-dimensional matrix with at least two rows")\n    if np.isinf(arr).any():\n        raise ValueError("X must not contain infinities")\n    return arr\n\n\ndef _validate_inputs(X, y, k, n_resamples, sample_fraction, threshold, sample_weight, groups, times, feature_names, n_jobs):\n    arr = _as_matrix(X)\n    yy = np.asarray(y, dtype=np.float64)\n    if yy.ndim != 1 or yy.shape[0] != arr.shape[0] or not np.all(np.isfinite(yy)):\n        raise ValueError("y must be a finite vector with one value per row")\n    p = arr.shape[1]\n    if not isinstance(k, (int, np.integer)) or isinstance(k, bool) or not 1 <= int(k) <= p:\n        raise ValueError("k must be an integer in [1, n_features]")\n    if not isinstance(n_resamples, (int, np.integer)) or isinstance(n_resamples, bool) or int(n_resamples) <= 0:\n        raise ValueError("n_resamples must be a positive integer")\n    if not np.isscalar(sample_fraction) or not np.isfinite(sample_fraction) or not 0 < float(sample_fraction) <= 1:\n        raise ValueError("sample_fraction must be in (0, 1]")\n    if not np.isscalar(threshold) or not np.isfinite(threshold) or not 0 <= float(threshold) <= 1:\n        raise ValueError("threshold must be in [0, 1]")\n    ww = None\n    if sample_weight is not None:\n        ww = np.asarray(sample_weight, dtype=np.float64)\n        if ww.ndim != 1 or ww.shape[0] != arr.shape[0] or not np.all(np.isfinite(ww)) or np.any(ww < 0) or not np.any(ww > 0):\n            raise ValueError("sample_weight must be finite, nonnegative, and have positive mass")\n    gg = None if groups is None else np.asarray(groups)\n    tt = None if times is None else np.asarray(times)\n    if gg is not None and (gg.ndim != 1 or gg.shape[0] != arr.shape[0]):\n        raise ValueError("groups must have one label per row")\n    if tt is not None and (tt.ndim != 1 or tt.shape[0] != arr.shape[0]):\n        raise ValueError("times must have one value per row")\n    if gg is not None and tt is not None:\n        raise ValueError("groups and times are mutually exclusive")\n    if tt is not None:\n        try:\n            numeric_times = tt.astype(np.float64)\n        except (TypeError, ValueError):\n            # Datetime-like arrays are accepted as long as they sort.\n            if np.any(np.equal(tt, None)):\n                raise ValueError("times must be sortable and non-null")\n        else:\n            if not np.all(np.isfinite(numeric_times)):\n                raise ValueError("times must be finite")\n    names = [str(i) for i in range(p)] if feature_names is None else [str(v) for v in feature_names]\n    if len(names) != p or len(set(names)) != len(names):\n        raise ValueError("feature_names must contain one unique name per feature")\n    if not isinstance(n_jobs, (int, np.integer)) or isinstance(n_jobs, bool) or int(n_jobs) <= 0:\n        raise ValueError("n_jobs must be a positive integer")\n    return arr, yy, int(k), int(n_resamples), float(sample_fraction), float(threshold), ww, gg, tt, names\n\n\ndef _indices_for_resample(n: int, target: int, rng: np.random.Generator, groups, times) -> np.ndarray:\n    if groups is not None:\n        labels, inverse = np.unique(groups, return_inverse=True)\n        order = rng.permutation(labels.shape[0])\n        chosen: list[int] = []\n        count = 0\n        for group_pos in order:\n            rows = np.flatnonzero(inverse == group_pos)\n            chosen.extend(rows.tolist())\n            count += rows.size\n            if count >= target:\n                break\n        return np.asarray(chosen, dtype=np.int64)\n    if times is not None:\n        # Stable sorting ensures equal timestamps retain input order.  Sampling\n        # the start point, rather than permuting rows, preserves temporal order.\n        try:\n            order = np.argsort(times, kind="stable")\n        except TypeError as exc:\n            raise ValueError("times must be sortable") from exc\n        start = int(rng.integers(0, n - target + 1))\n        return np.asarray(order[start : start + target], dtype=np.int64)\n    return np.sort(rng.choice(n, size=target, replace=False))\n\n\ndef _local_preprocess(X: np.ndarray, indices: np.ndarray) -> np.ndarray:\n    Z = np.asarray(X[indices], dtype=np.float64).copy()\n    # Compute each median and scale from this resample only.  A fully missing\n    # column has no information and is mapped to zero instead of leaking a\n    # global statistic.\n    for j in range(Z.shape[1]):\n        col = Z[:, j]\n        finite = np.isfinite(col)\n        if finite.any():\n            med = float(np.median(col[finite]))\n            col[~finite] = med\n            mean = float(np.mean(col))\n            sd = float(np.std(col))\n            if sd > 0:\n                col[:] = (col - mean) / sd\n            else:\n                col[:] = 0.0\n        else:\n            col[:] = 0.0\n    return Z\n\n\ndef _weighted_correlations(Z: np.ndarray, y: np.ndarray, weights: np.ndarray | None) -> np.ndarray:\n    w = np.ones(y.size, dtype=np.float64) if weights is None else np.asarray(weights, dtype=np.float64)\n    total = float(np.sum(w))\n    if total <= 0:\n        return np.zeros(Z.shape[1], dtype=np.float64)\n    yc = y - np.sum(w * y) / total\n    yvar = float(np.sum(w * yc * yc))\n    if yvar <= np.finfo(float).eps:\n        return np.zeros(Z.shape[1], dtype=np.float64)\n    zmean = np.sum(w[:, None] * Z, axis=0) / total\n    zc = Z - zmean\n    cov = np.sum(w[:, None] * zc * yc[:, None], axis=0)\n    zvar = np.sum(w[:, None] * zc * zc, axis=0)\n    denom = np.sqrt(np.maximum(zvar * yvar, 0.0))\n    out = np.zeros(Z.shape[1], dtype=np.float64)\n    np.divide(cov, denom, out=out, where=denom > np.finfo(float).eps)\n    return out\n\n\ndef stability_select(\n    X,\n    y,\n    *,\n    k,\n    n_resamples=100,\n    sample_fraction=0.5,\n    threshold=0.8,\n    sample_weight=None,\n    groups=None,\n    times=None,\n    feature_names: Sequence[str] | None = None,\n    random_state=0,\n    n_jobs=1,\n) -> StabilityResult:\n    """Select features repeatedly under deterministic row resampling.\n\n    Every replicate imputes missing values, centers, and scales from its own\n    sampled rows.  The top ``k`` absolute weighted Pearson correlations are\n    marked selected; features meeting ``threshold`` frequency are returned in\n    original column order.  ``n_jobs`` is accepted for API compatibility and\n    does not alter the seeded sequential computation.\n    """\n    arr, yy, k, n_resamples, sample_fraction, threshold, ww, gg, tt, names = _validate_inputs(\n        X, y, k, n_resamples, sample_fraction, threshold, sample_weight, groups, times, feature_names, n_jobs\n    )\n    n, p = arr.shape\n    target = max(1, int(np.ceil(n * sample_fraction)))\n    rng = np.random.default_rng(random_state)\n    hits = np.zeros(p, dtype=np.int64)\n    for _ in range(n_resamples):\n        idx = _indices_for_resample(n, target, rng, gg, tt)\n        Z = _local_preprocess(arr, idx)\n        corr = np.abs(_weighted_correlations(Z, yy[idx], None if ww is None else ww[idx]))\n        # argpartition is not stable at the cutoff, so sort the small final\n        # candidate set by (-score, original index) for deterministic ties.\n        order = np.lexsort((np.arange(p), -corr))\n        chosen = order[:k]\n        hits[chosen] += 1\n    frequencies = hits.astype(np.float64) / n_resamples\n    selected = np.flatnonzero(frequencies >= threshold).astype(int).tolist()\n    return StabilityResult(selected, [names[i] for i in selected], frequencies, threshold, n_resamples)\n\n\ndef _cli(argv: list[str] | None = None) -> None:\n    parser = argparse.ArgumentParser(description=__doc__)\n    parser.add_argument("--input", type=Path, default=Path("stability_input.npz"))\n    parser.add_argument("--output", type=Path, default=Path("outputs/stability.json"))\n    args = parser.parse_args(argv)\n    with np.load(args.input, allow_pickle=False) as data:\n        X, y = data["X"], data["y"]\n    config = json.loads(args.input.with_name("stability_config.json").read_text(encoding="utf-8"))\n    result = stability_select(X, y, **config)\n    payload = {\n        "selected_indices": result.selected_indices,\n        "selected_features": result.selected_features,\n        "frequencies": result.frequencies.tolist(),\n        "threshold": result.threshold,\n        "n_resamples": result.n_resamples,\n    }\n    args.output.parent.mkdir(parents=True, exist_ok=True)\n    args.output.write_text(json.dumps(payload, indent=2) + "\\n", encoding="utf-8")\n\n\nif __name__ == "__main__":\n    _cli()\n'
def main():
    workspace=Path(sys.argv[1]) if len(sys.argv)>1 else Path.cwd()
    (workspace/"stability.py").write_text(SOURCE,encoding="utf-8")
    os.chdir(workspace)
    sys.argv = [str(workspace/"stability.py")]
    runpy.run_path(str(workspace/"stability.py"),run_name="__main__")
if __name__=="__main__": main()
